// Lowercased skill name -> icon key.
const ALIASES: Record<string, string> = {
  "html": "html",
  "css": "css",
  "javascript": "javascript",
  "typescript": "typescript",
  "react": "react",
  "tailwind css": "tailwind",
  "tailwindcss": "tailwind",
  "three.js": "threejs",
  "threejs": "threejs",
  "framer motion": "framer",
  "c#": "dotnet",
  "asp.net core web api": "dotnet",
  "asp.net core": "dotnet",
  "entity framework core": "dotnet",
  ".net": "dotnet",
  "node.js": "nodejs",
  "nodejs": "nodejs",
  "mysql": "mysql",
  "flutter": "flutter",
  "dart": "dart",
  "sql server": "sqlserver",
};

export default function TechIcon({
  name,
  size = 14,
  className = "",
}: {
  name: string;
  size?: number;
  className?: string;
}) {
  const key = ALIASES[name.trim().toLowerCase()];
  const icon = key ? ICONS[key] : undefined;
  if (!icon) return null;

  return (
    <svg
      role="img"
      aria-hidden
      width={size}
      height={size}
      viewBox={icon.viewBox}
      fill={icon.color}
      className={className}
    >
      <path d={icon.path} />
    </svg>
  );
}
